// ─── Migration Analysis ─────────────────────────────────────────────

describe('parseMigrationNames', () => {
  it('parses migration dir names', () => {
    const result = parseMigrationNames(['20251011024518_init', '20260118_add_webhooks']);
    expect(result).toHaveLength(2);
    expect(result[0].timestamp).toBe('20251011024518');
    expect(result[1].timestamp).toBe('20260118');
  });

  it('skips lock files', () => {
    const result = parseMigrationNames(['migration_lock.toml', '20251011_init']);
    expect(result).toHaveLength(1);
  });

  it('sorts by timestamp', () => {
    const result = parseMigrationNames(['20260118_add', '20251011_init']);
    expect(result[0].name).toBe('20251011_init');
    expect(result[1].name).toBe('20260118_add');
  });
});

describe('parseTimestamp', () => {
  it('parses YYYYMMDDHHMMSS', () => {
    const d = parseTimestamp('20251011024518');
    expect(d).not.toBeNull();
    expect(d?.getFullYear()).toBe(2025);
    expect(d?.getMonth()).toBe(9); // October
    expect(d?.getDate()).toBe(11);
  });

  it('returns null for short strings', () => {
    expect(parseTimestamp('2025')).toBeNull();
  });
});

describe('checkMigrationHealth', () => {
  it('flags no migrations', () => {
    const issues = checkMigrationHealth([], 10);
    expect(issues.length).toBeGreaterThan(0);
    expect(issues[0].severity).toBe('error');
  });

  it('flags low migration count', () => {
    const migrations = [{ name: '20251011_init', timestamp: '20251011', hasDown: false }];
    const issues = checkMigrationHealth(migrations, 100);
    const lowCountIssue = issues.find((i) => i.message.includes('Low migration count'));
    expect(lowCountIssue).toBeDefined();
  });

  it('no issues for reasonable migration count', () => {
    const migrations = Array.from({ length: 10 }, (_, i) => ({
      name: `2025${String(i + 1).padStart(2, '0')}01_m${i}`,
      timestamp: `2025${String(i + 1).padStart(2, '0')}01`,
      hasDown: false,
    }));
    const issues = checkMigrationHealth(migrations, 20);
    const errorIssues = issues.filter((i) => i.severity === 'error');
    expect(errorIssues).toHaveLength(0);
  });
});

// ─── Report Generation ───────────────────────────────────────────────

describe('generateAuditReport', () => {
  const minimalSchema = `
model users {
  id    String @id
  email String @unique
  @@schema("public")
}
`;

  it('generates a valid report', () => {
    const report = generateAuditReport(minimalSchema, ['20251011_init']);
    expect(report.generatedAt).toBeDefined();
    expect(report.summary.totalModels).toBe(1);
    expect(report.models).toHaveLength(1);
    expect(typeof report.summary.totalIssues).toBe('number');
  });

  it('includes issues array', () => {
    const report = generateAuditReport(minimalSchema, []);
    expect(Array.isArray(report.issues)).toBe(true);
    // Should have at least a migration error because no migrations
    expect(report.issues.length).toBeGreaterThan(0);
  });
});

describe('formatReportText', () => {
  it('generates readable text output', () => {
    const report = generateAuditReport('model t { id String @id @@schema("public") }', ['20251011_init']);
    const text = formatReportText(report);
    expect(text).toContain('PRISMA SCHEMA AUDIT REPORT');
    expect(text).toContain('SUMMARY');
    expect(text).toContain('SCHEMA HEALTH SCORE');
  });
});

describe('computeHealthScore', () => {
  it('returns 100-range for clean report', () => {
    const report = generateAuditReport(
      `model users {
        id String @id
        createdAt DateTime @default(now())
        updatedAt DateTime @default(now())
        @@index([createdAt])
        @@schema("public")
      }`,
      ['20251011_init'],
    );
    const score = computeHealthScore(report);
    expect(score).toBeGreaterThanOrEqual(0);
    expect(score).toBeLessThanOrEqual(100);
  });

  it('deducts for errors', () => {
    const report = generateAuditReport('model t { id String @id @@schema("public") }', []);
    const score = computeHealthScore(report);
    expect(score).toBeLessThan(100);
  });
});
